INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/01/31 12:00:00", 3.414, 2, 62, 1, 1, 190805, "カリン", 0.0, 1000001, 1, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", -416.5);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/01/31 12:00:00", 3.099, 2, 62, 1, 2, 190805, "カリン", 0.0, 1000002, 1, "ミッションをクリアして、\n報酬をゲットしましょう！", -416.5);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/01/31 12:00:00", 2.801, 2, 63, 1, 3, 190805, "カリン", 0.0, 1000003, 1, "受け取ることができる\n報酬があるようです\n確認してみてください", -416.5);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/01/31 12:00:00", 0.0, 2, 63, 1, 4, 190805, "カリン", 0.0, 1000004, 2, "報酬がもらえますよ！\nチェックしてみてください", -416.5);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/01/31 12:00:00", 2.12, 1, 64, 1, 5, 190805, "カリン", 0.0, 1000005, 2, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", -363.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/01/31 12:00:00", 1.68, 2, 64, 1, 6, 190805, "カリン", 0.0, 1000006, 1, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", -363.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/01/31 12:00:00", 2.33, 1, 64, 1, 7, 190805, "カリン", 0.0, 1000007, 2, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", -363.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/01/31 12:00:00", 5.18, 7, 61, 10201, 101, 133701, "ラビリスタ", -6.0, 1020101, 3, "今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/01/31 12:00:00", 8.77, 2, 61, 10201, 201, 133901, "クリスティーナ", -2.0, 1020102, 1, "退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/01/31 12:00:00", 15.5, 1, 61, 10201, 301, 133801, "ネネカ", 0.0, 1020103, 6, "おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/02/28 12:00:00", 9.061, 5, 61, 10202, 101, 134301, "ランファ", 0.0, 1020201, 2, "わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/02/28 12:00:00", 7.699, 2, 61, 10202, 201, 134401, "チカ", 0.0, 1020202, 1, "同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/03/31 12:00:00", 8.595, 2, 61, 10203, 101, 134601, "アオイ", 0.0, 1020301, 1, "世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/03/31 12:00:00", 7.758, 2, 61, 10203, 201, 134501, "クローチェ", 0.0, 1020302, 1, "新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/04/30 12:00:00", 7.0, 6, 61, 10204, 101, 132302, "ルイズマリー", 0.0, 1020401, 2, "今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/04/30 12:00:00", 7.904, 2, 61, 10204, 201, 132402, "イロハ", 0.0, 1020402, 1, "ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/04/30 12:00:00", 8.487, 2, 61, 10204, 301, 132502, "ソノ", 0.0, 1020403, 4, "ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/05/31 12:00:00", 8.763, 2, 61, 10205, 101, 134901, "カノン", 0.0, 1020502, 1, "ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/05/31 12:00:00", 6.417, 3, 61, 10205, 201, 134801, "ツムギ", 0.0, 1020503, 1, "いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/06/30 12:00:00", 10.335, 7, 61, 10206, 101, 135001, "エリス", 0.0, 1020601, 3, "『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/06/30 12:00:00", 6.281, 4, 61, 10206, 201, 135101, "シェフィ", 0.0, 1020602, 2, "せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/06/30 12:00:00", 12.244, 2, 61, 10206, 301, 135201, "プレシア", 0.0, 1020603, 1, "いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/07/31 12:00:00", 6.339, 8, 61, 10207, 101, 135301, "クリア", 0.0, 1020701, 2, "ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/07/31 12:00:00", 8.184, 9, 61, 10207, 201, 135401, "アネモネ", 0.0, 1020702, 7, "─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/08/31 12:00:00", 3.906, 2, 61, 10208, 101, 129101, "アイラ", 0.0, 1020801, 9, "あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/08/31 12:00:00", 14.465, 2, 61, 10208, 201, 129201, "シナツ", 0.0, 1020802, 1, "繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/08/31 12:00:00", 8.662, 3, 61, 10208, 301, 100101, "ヒヨリ", 0.0, 1020803, 4, "アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/08/31 12:00:00", 10.915, 3, 61, 10208, 401, 100301, "レイ", 0.0, 1020804, 1, "シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/09/30 12:00:00", 6.042, 7, 61, 10209, 101, 135802, "ユキノ", 0.0, 1020901, 1, "あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/09/30 12:00:00", 9.402, 1, 61, 10209, 201, 135903, "サツキ", 0.0, 1020902, 4, "なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/09/30 12:00:00", 8.16, 1, 61, 10209, 301, 136902, "ルルィ", 0.0, 1020903, 8, "う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/10/31 12:00:00", 5.0, 2, 61, 10210, 101, 137401, "カスミ", 0.0, 1021001, 3, "ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/10/31 12:00:00", 8.12, 1, 61, 10210, 201, 136001, "アラクネ", 0.0, 1021002, 4, "…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/10/31 12:00:00", 6.386, 2, 61, 10210, 301, 136202, "ナーナ", 0.0, 1021003, 4, "ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/11/30 12:00:00", 7.438, 4, 61, 10211, 101, 136402, "ユイ", 0.0, 1021101, 3, "騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/11/30 12:00:00", 8.35, 5, 61, 10211, 201, 136302, "ミソラ", 0.0, 1021102, 1, "騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/12/31 12:00:00", 5.0, 2, 61, 10212, 101, 136501, "シズル", 0.0, 1021201, 1, "新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/12/31 12:00:00", 5.25, 2, 61, 10212, 201, 137902, "リノ", 0.0, 1021202, 1, "おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2025/12/31 12:00:00", 7.5, 2, 61, 10212, 301, 106801, "ラビリスタ", 0.0, 1021203, 1, "年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2026/01/31 12:00:00", 8.204, 2, 61, 10213, 101, 126501, "ライラエル", 0.0, 1021301, 1, "漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2026/01/31 12:00:00", 7.176, 2, 61, 10213, 201, 129701, "ネフィ＝ネラ", 0.0, 1021302, 1, "異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2026/01/31 12:00:00", 8.602, 5, 61, 10213, 301, 133101, "ヴァイオレット", 0.0, 1021303, 1, "『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2026/02/06 12:00:00", 10.14, 3, 61, 10213, 102, 138101, "ライラエル", 0.0, 1021304, 1, "多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2026/02/06 12:00:00", 10.152, 7, 61, 10213, 202, 138201, "ネフィ＝ネラ", 0.0, 1021305, 1, "煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2026/02/06 12:00:00", 9.688, 3, 61, 10213, 302, 138001, "ヴァイオレット", 0.0, 1021306, 4, "裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2026/02/12 12:00:00", 5.928, 1, 61, 10213, 401, 138301, "ペコリーヌ", 0.0, 1021307, 2, "みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2026/02/28 12:00:00", 9.19, 2, 61, 10214, 101, 138702, "ワカナ", 0.0, 1021401, 4, "成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", "2026/02/28 12:00:00", 8.724, 3, 61, 10214, 201, 138802, "シオリ", 0.0, 1021402, 1, "「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！", -285.0);
